1	const PROCESSING_FEE = 5;
2	const INITIAL_ASSESSMENT_SURCHARGE_RATE = 0.1;
3	
4	type Item = { type: string };
5	type QuoteStep = { op: "quote"; items: Item[] };
6	type Scenario = {
7	  customer: { yearsWithMHPCO: number };
8	  steps: QuoteStep[];
9	};
10	type QuoteResult = { premium: number };
11	type ScenarioResult = { results: QuoteResult[] };
12	
13	const BASE_PREMIUM: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	  rune: 25,
19	  moonstone: 25,
20	};
21	
22	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
23	const BLOCK_OF_THREE_PREMIUM = 60;
24	
25	const priceGroup = (type: string, count: number): number =>
26	  COMPONENT_TYPES.has(type) && count === 3
27	    ? BLOCK_OF_THREE_PREMIUM
28	    : count * BASE_PREMIUM[type];
29	
30	const countByType = (items: Item[]): Map<string, number> => {
31	  const counts = new Map<string, number>();
32	  for (const item of items) {
33	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
34	  }
35	  return counts;
36	};
37	
38	const sumBasePremiums = (items: Item[]): number => {
39	  let total = 0;
40	  for (const [type, count] of countByType(items)) {
41	    total += priceGroup(type, count);
42	  }
43	  return total;
44	};
45	
46	const quotePremium = (items: Item[]): number => {
47	  const base = sumBasePremiums(items);
48	  const surcharge = base * INITIAL_ASSESSMENT_SURCHARGE_RATE;
49	  return Math.ceil(base + surcharge) + PROCESSING_FEE;
50	};
51	
52	export const runScenario = (input: Scenario): ScenarioResult => {
53	  const results = input.steps.map((step) => ({ premium: quotePremium(step.items) }));
54	  return { results };
55	};
